export interface DevWorkshopPageProps {
  /** Path to the project's main CSS file (Tokens tab "Save" button).
   *  Defaults to `"src/index.css"`. */
  tokensCssFile?: string;
}

export type Tab = "props" | "tokens" | "code" | "element";

export default function DevWorkshopPage({ tokensCssFile = "src/index.css" }: DevWorkshopPageProps) {
  const [selected, setSelected] = useState<ComponentEntry | null>(componentEntries[0] ?? null);
  const [variantIndex, setVariantIndex] = useState(0);
  const [variantExplicit, setVariantExplicit] = useState(false);
  const [argsOverride, setArgsOverride] = useState<ArgsOverride>({});
  const [selectedEl, setSelectedEl] = useState<SelectedElement | null>(null);
  const [outlineHidden, setOutlineHidden] = useState(false);
  const [tab, setTab] = useState<Tab>("props");

  const [sidebarWidth, setSidebarWidth] = useState(() => readLSNumber(LS_SIDEBAR, 240));
  const [panelWidth, setPanelWidth] = useState(() => readLSNumber(LS_PANEL, 360));

  useEffect(() => localStorage.setItem(LS_SIDEBAR, String(sidebarWidth)), [sidebarWidth]);
  useEffect(() => localStorage.setItem(LS_PANEL, String(panelWidth)), [panelWidth]);

  const handleSelect = useCallback((entry: ComponentEntry, variantIdx: number | null = null) => {
    setSelected(entry);
    setVariantIndex(variantIdx ?? 0);
    setVariantExplicit(variantIdx !== null);
    setArgsOverride({});
    setSelectedEl(null);
    setOutlineHidden(false);
  }, []);

  const handleVariantChange = useCallback((i: number) => {
    setVariantIndex(i);
    setVariantExplicit(true);
    setArgsOverride({});
    setSelectedEl(null);
    setOutlineHidden(false);
  }, []);

  // Auto-switch to Element tab when something is selected via canvas click
  useEffect(() => {
    if (selectedEl) setTab("element");
  }, [selectedEl]);

  const inspectMode = tab === "element";

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key !== "Escape") return;
      if (selectedEl && !outlineHidden) setOutlineHidden(true);
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [selectedEl, outlineHidden]);

  useEffect(() => { if (selectedEl) setOutlineHidden(false); }, [selectedEl?.element]);

  // Keep selectedEl.element in sync with live DOM after HMR-driven remounts.
  useEffect(() => {
    const src = selectedEl?.source;
    if (!src) return;
    const selector = `[data-devsource="${src.file}:${src.line}:${src.column}"]`;
    const resolve = () => {
      const fresh = document.querySelector(selector);
      if (!fresh || fresh === selectedEl?.element) return;
      setSelectedEl({ element: fresh, source: src });
    };
    const root = document.querySelector("[data-dev-workshop]") ?? document.body;
    const mo = new MutationObserver(resolve);
    mo.observe(root, { childList: true, subtree: true, attributes: true });
    resolve();
    return () => mo.disconnect();
  }, [selectedEl?.source, selectedEl?.element]);

  const startResize = (which: "sidebar" | "panel") => (e: React.MouseEvent) => {
    e.preventDefault();
    const startX = e.clientX;
    const startW = which === "sidebar" ? sidebarWidth : panelWidth;
    const sign = which === "sidebar" ? 1 : -1;
    const onMove = (ev: MouseEvent) => {
      const next = Math.max(which === "sidebar" ? MIN_SIDEBAR : MIN_PANEL, Math.min(MAX_WIDTH, startW + (ev.clientX - startX) * sign));
      if (which === "sidebar") setSidebarWidth(Math.round(next));
      else setPanelWidth(Math.round(next));
    };
    const onUp = () => { window.removeEventListener("mousemove", onMove); window.removeEventListener("mouseup", onUp); document.body.style.cursor = ""; };
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);
    document.body.style.cursor = "ew-resize";
  };

  if (!selected) {
    return (
      <>
        <style>{STYLES}</style>
        <NoStoriesState />
      </>
    );
  }

  return (
    <>
      <style>{STYLES}</style>
      <div data-dev-workshop style={{ position: "fixed", inset: 0, zIndex: 0, display: "flex", background: "#F4F4F4", color: "#101114", padding: 12, gap: 0 }}>
        <ComponentSidebar
          entries={componentEntries}
          selectedId={selected.id}
          variantIndex={variantIndex}
          variantExplicit={variantExplicit}
          width={sidebarWidth}
          onSelect={handleSelect}
        />
        <button className="dw-resize" onMouseDown={startResize("sidebar")} title="Drag to resize" aria-label="resize sidebar" />
        <ComponentPreview
          key={selected.id}
          entry={selected}
          variantIndex={variantIndex}
          onVariantChange={handleVariantChange}
          argsOverride={argsOverride}
          selected={selectedEl}
          onSelectElement={setSelectedEl}
          hideSelectionOutline={outlineHidden}
          inspectMode={inspectMode}
        />
        <button className="dw-resize" onMouseDown={startResize("panel")} title="Drag to resize" aria-label="resize panel" />
        <div style={{ width: panelWidth, display: "flex", height: "100%", flexShrink: 0 }}>
          <StylePanel
            entry={selected}
            variantIndex={variantIndex}
            argsOverride={argsOverride}
            onArgsOverrideChange={setArgsOverride}
            selectedElement={selectedEl}
            onDeselectElement={() => setSelectedEl(null)}
            tokensCssFile={tokensCssFile}
            tab={tab}
            onTabChange={setTab}
          />
        </div>
      </div>
    </>
  );
}

/**
 * Empty state shown when no `*.stories.tsx` files were found by the
 * `storiesGlob`. Offers a one-click "Generate stubs" action that walks
 * the consumer's `componentsGlob` and writes stub stories next to each
 * default-exported component. After a successful run we reload — Vite
 * picks up the new files and the workshop fills with components.
 */
function NoStoriesState() {
  type Status = "idle" | "running" | "done" | "error";
  const [status, setStatus] = useState<Status>("idle");
  const [message, setMessage] = useState<string>("");

  const componentFiles = Object.keys(componentModules);
  const hasComponents = componentFiles.length > 0;

  const onGenerate = useCallback(async () => {
    setStatus("running");
    setMessage(`Scanning ${componentFiles.length} files…`);
    try {
      const result = await generateStubs(componentFiles);
      const skippedExisting = result.skipped.filter((s) => s.reason === "stories file already exists").length;
      const skippedOther = result.skipped.length - skippedExisting;
      const parts = [
        `Created ${result.created.length} stub${result.created.length === 1 ? "" : "s"}.`,
        skippedExisting ? `${skippedExisting} already had stories.` : null,
        skippedOther ? `${skippedOther} skipped (no default-exported component).` : null,
      ].filter(Boolean);
      setStatus("done");
      setMessage(parts.join(" "));
      if (result.created.length > 0) {
        setTimeout(() => window.location.reload(), 800);
      }
    } catch (err) {
      setStatus("error");
      setMessage(err instanceof Error ? err.message : String(err));
    }
  }, [componentFiles]);

  return (
    <>
      <div data-dev-workshop style={{ position: "fixed", inset: 0, zIndex: 0, display: "flex", alignItems: "center", justifyContent: "center", background: "#F4F4F4", color: "#101114" }}>
        <div style={{ textAlign: "center", maxWidth: 460, padding: 24 }}>
          <div style={{ fontSize: 22, fontWeight: 600 }}>No stories found yet</div>
          <div style={{ marginTop: 8, fontSize: 14, color: "#606060", lineHeight: 1.5 }}>
            Stories are <code className="dw-mono">*.stories.tsx</code> files placed next to your components.
            {hasComponents
              ? <> We found <strong>{componentFiles.length}</strong> component file{componentFiles.length === 1 ? "" : "s"} matching <code className="dw-mono">{componentsGlobPattern}</code>. Generate stub stories for them and you'll be up and running in a second.</>
              : <> No component files match <code className="dw-mono">{componentsGlobPattern}</code> — adjust the <code className="dw-mono">componentsGlob</code> plugin option, or write a stories file by hand. See the README for the format.</>
            }
          </div>

          {hasComponents && (
            <button
              onClick={onGenerate}
              disabled={status === "running" || status === "done"}
              className="dw-btn-primary"
              style={{ marginTop: 20, width: "auto", padding: "10px 18px", fontSize: 13 }}
            >
              {status === "running" ? "Generating…" : status === "done" ? "Reloading…" : "Generate stubs from " + componentsGlobPattern}
            </button>
          )}

          {message && (
            <div style={{ marginTop: 14, fontSize: 12, color: status === "error" ? "#e6365a" : "#1f9d55", lineHeight: 1.5 }}>
              {message}
            </div>
          )}
        </div>
      </div>
    </>
  );
}
